#nullable enable

using BepInEx;
using SkipDropshipCompany.Core.Ports;
using SkipDropshipCompany.Core.Validation;
using SkipDropshipCompany.Interop;
using SkipDropshipCompany.Interop.Game.Patches;

namespace SkipDropshipCompany;

// MyPluginInfo is generated by BepInEx.PluginInfoProps at build time. Keep the
// entrypoint metadata and startup log tied to that generated plugin identity.
[BepInPlugin(MyPluginInfo.PLUGIN_GUID, MyPluginInfo.PLUGIN_NAME, MyPluginInfo.PLUGIN_VERSION)]
[BepInProcess("Lethal Company.exe")]
public class SkipDropshipCompany : BaseUnityPlugin
{
    private static PluginController? controller;
    private static CallbackDiagnosticReporter? callbackDiagnostics;

    internal static PluginController Controller => controller!;

    internal static CallbackDiagnosticReporter CallbackDiagnostics => callbackDiagnostics!;

    private void Awake()
    {
        var logger = new BepInExPluginLogger(base.Logger);
        var config = BepInExPluginConfig.Bind(Config);
        IValidationLogger validationLogger = config.ValidationLogging
            ? new BepInExValidationLogger(logger, System.DateTime.UtcNow)
            : DisabledValidationLogger.Instance;

        validationLogger.Record(
            ValidationLogRecord.PluginLoaded(
                version: MyPluginInfo.PLUGIN_VERSION,
                validationLogging: config.ValidationLogging,
                enabled: config.Enabled,
                requireReroutingOnFirstDay: config.RequireReroutingOnFirstDay
            )
        );

        callbackDiagnostics = new CallbackDiagnosticReporter(
            logger: logger,
            validationLogger: validationLogger
        );
        controller = PluginController.Create(
            config: config,
            logger: logger,
            validationLogger: validationLogger
        );

        HarmonyPatchInstaller.Install();

        logger.LogInfo($"Plugin {MyPluginInfo.PLUGIN_NAME} v{MyPluginInfo.PLUGIN_VERSION} is loaded!");
    }
}
